declare const _default: "/*! Asciidoctor semantic HTML5 default stylesheet | MIT License | https://asciidoctor.org */\n\n/* \u2500\u2500 Tokens \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\n:root {\n  color-scheme: light dark;\n  --asciidoctor-bg: #fdfdfc;\n  --asciidoctor-surface: #f6f5f3;\n  --asciidoctor-fg: #23282e;\n  --asciidoctor-muted: #5c646e;\n  --asciidoctor-line: #e5e3df;\n  --asciidoctor-link: #0958b0;\n  --asciidoctor-mark: #fff2ae;\n  --asciidoctor-note: #0969da;\n  --asciidoctor-tip: #1a7f37;\n  --asciidoctor-important: #8250df;\n  --asciidoctor-warning: #9a6700;\n  --asciidoctor-caution: #cf222e;\n}\n\n@media (prefers-color-scheme: dark) {\n  :root {\n    --asciidoctor-bg: #16181c;\n    --asciidoctor-surface: #1e2126;\n    --asciidoctor-fg: #e6e7e9;\n    --asciidoctor-muted: #9aa2ac;\n    --asciidoctor-line: #2c313a;\n    --asciidoctor-link: #6cb0f5;\n    --asciidoctor-mark: #6b5d1a;\n    --asciidoctor-note: #4493f8;\n    --asciidoctor-tip: #3fb950;\n    --asciidoctor-important: #ab7df8;\n    --asciidoctor-warning: #d29922;\n    --asciidoctor-caution: #f85149;\n  }\n}\n\n/* \u2500\u2500 Base \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\n*,\n*::before,\n*::after {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0 auto;\n  max-width: 47rem;\n  padding: 1.5rem 1.25rem 3rem;\n  background: var(--asciidoctor-bg);\n  color: var(--asciidoctor-fg);\n  font-family:\n    system-ui,\n    -apple-system,\n    \"Segoe UI\",\n    Roboto,\n    \"Noto Sans\",\n    sans-serif;\n  font-size: 1.0625rem;\n  line-height: 1.7;\n  -webkit-text-size-adjust: 100%;\n  overflow-wrap: break-word;\n}\n\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  line-height: 1.25;\n  letter-spacing: -0.01em;\n  font-weight: 600;\n  margin: 2em 0 0.6em;\n  text-wrap: balance;\n}\n\nh1 {\n  font-size: 2rem;\n}\nh2 {\n  font-size: 1.5rem;\n}\nh3 {\n  font-size: 1.25rem;\n}\nh4 {\n  font-size: 1.0625rem;\n}\nh5,\nh6 {\n  font-size: 1rem;\n}\n\np {\n  margin: 0 0 1em;\n}\n\na {\n  color: var(--asciidoctor-link);\n  text-decoration: none;\n}\na:hover {\n  text-decoration: underline;\n}\na:focus-visible {\n  outline: 2px solid var(--asciidoctor-link);\n  outline-offset: 2px;\n  border-radius: 2px;\n}\n\ncode,\nkbd,\npre,\nsamp {\n  font-family:\n    ui-monospace,\n    \"SF Mono\",\n    \"Cascadia Code\",\n    Menlo,\n    Consolas,\n    monospace;\n}\n\ncode {\n  font-size: 0.875em;\n  background: var(--asciidoctor-surface);\n  padding: 0.1em 0.3em;\n  border-radius: 4px;\n}\n\npre {\n  margin: 0;\n  padding: 1rem 1.25rem;\n  overflow-x: auto;\n  font-size: 0.875rem;\n  line-height: 1.6;\n  background: var(--asciidoctor-surface);\n  border-radius: 8px;\n}\npre code {\n  background: none;\n  padding: 0;\n  font-size: inherit;\n  border-radius: 0;\n}\npre.no-wrap {\n  white-space: pre;\n}\n\nmark {\n  background: var(--asciidoctor-mark);\n  color: inherit;\n  padding: 0 0.15em;\n  border-radius: 2px;\n}\n\nhr {\n  border: 0;\n  border-top: 1px solid var(--asciidoctor-line);\n  margin: 2.5rem 0;\n}\n\nimg,\nsvg,\nvideo {\n  max-width: 100%;\n  height: auto;\n}\n\nsub,\nsup {\n  font-size: 0.75em;\n  line-height: 0;\n}\n\n/* \u2500\u2500 Document header \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nbody > header {\n  margin-bottom: 2.5rem;\n  padding-bottom: 1.25rem;\n  border-bottom: 1px solid var(--asciidoctor-line);\n}\n\nbody > header h1 {\n  margin: 0 0 0.25rem;\n  font-size: 2.25rem;\n}\n\nbody > header h1 .subtitle {\n  display: block;\n  font-size: 0.55em;\n  font-weight: 400;\n  color: var(--asciidoctor-muted);\n  letter-spacing: 0;\n}\n\n.byline {\n  margin: 0.5rem 0 0;\n  color: var(--asciidoctor-muted);\n  font-size: 0.9375rem;\n}\nul.byline {\n  list-style: none;\n  padding: 0;\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.25rem 1.5rem;\n}\nul.byline li {\n  margin: 0;\n}\n\ntable.revision {\n  margin-top: 0.75rem;\n  font-size: 0.8125rem;\n  color: var(--asciidoctor-muted);\n  border-collapse: collapse;\n}\ntable.revision thead {\n  position: absolute;\n  width: 1px;\n  height: 1px;\n  overflow: hidden;\n  clip-path: inset(50%);\n}\ntable.revision td {\n  padding: 0 1.25rem 0 0;\n}\ntable.revision td:empty {\n  display: none;\n}\ntable.revision td::before {\n  content: attr(data-title) \" \";\n}\ntable.revision td[data-title=\"\"]::before,\ntable.revision td[data-title=\"Date\"]::before,\ntable.revision td[data-title=\"Remark\"]::before {\n  content: none;\n}\n\n/* \u2500\u2500 Page footer \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nbody > footer {\n  margin-top: 3rem;\n  padding-top: 1rem;\n  border-top: 1px solid var(--asciidoctor-line);\n  font-size: 0.8125rem;\n  color: var(--asciidoctor-muted);\n  display: flex;\n  flex-wrap: wrap;\n  gap: 0.25rem 1.5rem;\n}\n\n/* \u2500\u2500 Sections \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\n.sect-num {\n  color: var(--asciidoctor-muted);\n  font-weight: 500;\n  margin-right: 0.25em;\n}\n\n/* :sectanchors: \u2014 reveal the anchor on heading hover */\na.anchor {\n  float: left;\n  margin-left: -1.1em;\n  width: 1.1em;\n  visibility: hidden;\n  font-weight: 400;\n}\na.anchor::before {\n  content: \"\u00A7\";\n}\nh1:hover a.anchor,\nh2:hover a.anchor,\nh3:hover a.anchor,\nh4:hover a.anchor,\nh5:hover a.anchor,\nh6:hover a.anchor {\n  visibility: visible;\n}\n\n/* :sectlinks: \u2014 self-links keep the heading color */\nh1 > a.link,\nh2 > a.link,\nh3 > a.link,\nh4 > a.link,\nh5 > a.link,\nh6 > a.link {\n  color: inherit;\n}\n\n/* \u2500\u2500 Block titles \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nstrong.title {\n  display: block;\n  margin-bottom: 0.25em;\n}\n\n/* \u2500\u2500 Table of contents \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nnav.toc {\n  margin: 1.5rem 0;\n  padding: 1rem 1.25rem;\n  background: var(--asciidoctor-surface);\n  border: 1px solid var(--asciidoctor-line);\n  border-radius: 8px;\n}\nnav.toc > .title {\n  font-size: 0.75rem;\n  font-weight: 600;\n  text-transform: uppercase;\n  letter-spacing: 0.1em;\n  color: var(--asciidoctor-muted);\n  margin-bottom: 0.5rem;\n}\nnav.toc ol {\n  list-style: none;\n  margin: 0;\n  padding: 0;\n}\nnav.toc ol ol {\n  padding-left: 1rem;\n}\nnav.toc li {\n  margin: 0.2em 0;\n}\nnav.toc a {\n  color: var(--asciidoctor-fg);\n  font-size: 0.9375rem;\n}\nnav.toc a:hover {\n  color: var(--asciidoctor-link);\n}\n\n/* \u2500\u2500 Admonitions \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\naside.admonition {\n  --asciidoctor-admonition: var(--asciidoctor-muted);\n  margin: 1.5rem 0;\n  padding: 0.5rem 1.25rem;\n  border-left: 0.25rem solid var(--asciidoctor-admonition);\n}\naside.admonition.note {\n  --asciidoctor-admonition: var(--asciidoctor-note);\n}\naside.admonition.tip {\n  --asciidoctor-admonition: var(--asciidoctor-tip);\n}\naside.admonition.important {\n  --asciidoctor-admonition: var(--asciidoctor-important);\n}\naside.admonition.warning {\n  --asciidoctor-admonition: var(--asciidoctor-warning);\n}\naside.admonition.caution {\n  --asciidoctor-admonition: var(--asciidoctor-caution);\n}\naside.admonition > .label,\naside.admonition > .icon,\naside.admonition > i.fa {\n  display: block;\n  color: var(--asciidoctor-admonition);\n  font-weight: 600;\n  margin-bottom: 0.25em;\n}\naside.admonition > p:last-child {\n  margin-bottom: 0;\n}\n\n/* \u2500\u2500 Sidebar \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\naside.sidebar {\n  margin: 1.5rem 0;\n  padding: 1rem 1.25rem;\n  background: var(--asciidoctor-surface);\n  border-radius: 8px;\n}\naside.sidebar > :last-child {\n  margin-bottom: 0;\n}\n\n/* \u2500\u2500 Figures \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nfigure {\n  margin: 1.5rem 0;\n}\nfigcaption {\n  font-size: 0.875rem;\n  color: var(--asciidoctor-muted);\n  margin: 0.4rem 0;\n}\nfigcaption .label {\n  font-weight: 600;\n}\n\nfigure.listing figcaption,\nfigure.literal figcaption,\nfigure.example figcaption,\nfigure.stem figcaption {\n  margin-top: 0;\n}\n\nfigure.example {\n  padding: 1rem 1.25rem;\n  border: 1px solid var(--asciidoctor-line);\n  border-radius: 8px;\n}\nfigure.example > :last-child {\n  margin-bottom: 0;\n}\nfigure.example > figcaption {\n  margin: -0.25rem 0 0.75rem;\n}\n\nfigure.stem {\n  text-align: center;\n}\n\n/* collapsible example */\ndetails {\n  margin: 1.5rem 0;\n  padding: 0.75rem 1.25rem;\n  border: 1px solid var(--asciidoctor-line);\n  border-radius: 8px;\n}\ndetails > summary {\n  cursor: pointer;\n  font-weight: 600;\n}\ndetails[open] > summary {\n  margin-bottom: 0.5rem;\n}\n\n/* \u2500\u2500 Quote and verse \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nblockquote {\n  margin: 1.5rem 0;\n  padding: 0.25rem 0 0.25rem 1.25rem;\n  border-left: 0.25rem solid var(--asciidoctor-line);\n}\nblockquote.quote {\n  font-style: italic;\n}\nblockquote footer {\n  margin-top: 0.5rem;\n  font-style: normal;\n  font-size: 0.875rem;\n  color: var(--asciidoctor-muted);\n}\nblockquote pre {\n  background: none;\n  padding: 0;\n  font-family: inherit;\n  font-size: inherit;\n  white-space: pre-wrap;\n}\nfigure.quote > blockquote,\nfigure.verse > blockquote {\n  margin: 0.5rem 0 0;\n}\n\n/* \u2500\u2500 Lists \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nul,\nol,\ndl {\n  margin: 0 0 1em;\n}\nli > p,\ndd > p {\n  margin-bottom: 0.25em;\n}\ndt {\n  font-weight: 600;\n}\ndd {\n  margin: 0 0 0.5em 1.25rem;\n}\n\nul.checklist {\n  list-style: none;\n  padding-left: 1.5rem;\n}\n\n/* qanda \u2014 number the questions with a counter */\ndl.qanda {\n  counter-reset: question;\n}\ndl.qanda dt::before {\n  counter-increment: question;\n  content: counter(question) \". \";\n}\n\n/* horizontal dlist \u2014 two-column grid */\ndl.horizontal {\n  display: grid;\n  grid-template-columns: minmax(6rem, max-content) 1fr;\n  gap: 0.25em 1.5rem;\n}\ndl.horizontal dt {\n  grid-column: 1;\n}\ndl.horizontal dd {\n  grid-column: 2;\n  margin: 0;\n}\n\n/* \u2500\u2500 Callouts \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nb.callout-num {\n  color: var(--asciidoctor-muted);\n  font-weight: 600;\n  font-family:\n    system-ui,\n    -apple-system,\n    \"Segoe UI\",\n    sans-serif;\n  font-size: 0.8125em;\n}\ni.conum[data-value] {\n  display: inline-block;\n  min-width: 1.3em;\n  height: 1.3em;\n  border-radius: 50%;\n  background: var(--asciidoctor-muted);\n  color: var(--asciidoctor-bg);\n  font-size: 0.75em;\n  font-weight: 600;\n  font-style: normal;\n  font-family:\n    system-ui,\n    -apple-system,\n    \"Segoe UI\",\n    sans-serif;\n  line-height: 1.3em;\n  text-align: center;\n}\ni.conum[data-value]::after {\n  content: attr(data-value);\n}\ni.conum[data-value] + b {\n  display: none;\n}\n\nol.callout-list {\n  list-style: none;\n  counter-reset: callout;\n  padding-left: 0;\n  font-size: 0.9375rem;\n}\nol.callout-list > li {\n  counter-increment: callout;\n  margin: 0.25em 0;\n}\nol.callout-list > li > p::before {\n  content: counter(callout);\n  display: inline-block;\n  min-width: 1.3em;\n  height: 1.3em;\n  margin-right: 0.5em;\n  border-radius: 50%;\n  background: var(--asciidoctor-muted);\n  color: var(--asciidoctor-bg);\n  font-size: 0.75em;\n  font-weight: 600;\n  line-height: 1.3em;\n  text-align: center;\n}\n/* in icons mode the marker is already in the content \u2014 drop the counter */\nol.callout-list > li > p:has(> i.conum:first-child)::before,\nol.callout-list > li > p:has(> img:first-child)::before {\n  content: none;\n}\n\n/* \u2500\u2500 Tables \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\ntable {\n  border-collapse: collapse;\n  margin: 1.5rem 0;\n  font-size: 0.9375rem;\n}\ntable caption {\n  text-align: left;\n  font-size: 0.875rem;\n  color: var(--asciidoctor-muted);\n  margin-bottom: 0.4rem;\n}\nth,\ntd {\n  padding: 0.4rem 0.75rem;\n  text-align: left;\n  vertical-align: top;\n}\nthead th {\n  font-weight: 600;\n}\ntd > p:last-child {\n  margin-bottom: 0;\n}\n\ntable.stretch {\n  width: 100%;\n}\ntable.fit-content {\n  width: fit-content;\n}\n\n/* frame */\ntable.frame-all {\n  border: 1px solid var(--asciidoctor-line);\n}\ntable.frame-ends {\n  border-top: 1px solid var(--asciidoctor-line);\n  border-bottom: 1px solid var(--asciidoctor-line);\n}\ntable.frame-sides {\n  border-left: 1px solid var(--asciidoctor-line);\n  border-right: 1px solid var(--asciidoctor-line);\n}\n\n/* grid */\ntable[class*=\"grid-\"] > * > tr > th,\ntable[class*=\"grid-\"] > * > tr > td {\n  border: 0 solid var(--asciidoctor-line);\n}\ntable.grid-all > * > tr > th,\ntable.grid-all > * > tr > td {\n  border-width: 1px;\n}\ntable.grid-rows > * > tr > th,\ntable.grid-rows > * > tr > td {\n  border-width: 1px 0;\n}\ntable.grid-cols > * > tr > th,\ntable.grid-cols > * > tr > td {\n  border-width: 0 1px;\n}\n\n/* stripes */\ntable.stripes-all > tbody > tr,\ntable.stripes-even > tbody > tr:nth-of-type(even),\ntable.stripes-odd > tbody > tr:nth-of-type(odd) {\n  background: var(--asciidoctor-surface);\n}\ntable.stripes-hover > tbody > tr:hover {\n  background: var(--asciidoctor-surface);\n}\n\n/* cell alignment */\nth.halign-center,\ntd.halign-center {\n  text-align: center;\n}\nth.halign-right,\ntd.halign-right {\n  text-align: right;\n}\nth.valign-middle,\ntd.valign-middle {\n  vertical-align: middle;\n}\nth.valign-bottom,\ntd.valign-bottom {\n  vertical-align: bottom;\n}\n\n/* \u2500\u2500 Footnotes \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nsup.footnote-ref {\n  font-size: 0.75em;\n}\nsection.footnotes {\n  margin-top: 3rem;\n  font-size: 0.875rem;\n  color: var(--asciidoctor-muted);\n}\nsection.footnotes > hr {\n  width: 8rem;\n  margin: 0 0 1rem;\n}\nol.footnotes {\n  padding-left: 1.5rem;\n}\na.footnote-backref {\n  text-decoration: none;\n}\n\n/* \u2500\u2500 Inline UI macros \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\nkbd {\n  display: inline-block;\n  font-size: 0.75em;\n  line-height: 1.4;\n  padding: 0.1em 0.45em;\n  border: 1px solid var(--asciidoctor-line);\n  border-bottom-width: 2px;\n  border-radius: 4px;\n  background: var(--asciidoctor-surface);\n}\n.key-seq kbd {\n  margin: 0 0.1em;\n}\n\n.button {\n  font-weight: 600;\n  font-size: 0.875em;\n  padding: 0.05em 0.5em;\n  border: 1px solid var(--asciidoctor-line);\n  border-radius: 6px;\n  background: var(--asciidoctor-surface);\n  white-space: nowrap;\n}\n\n.menu-seq b {\n  font-weight: 600;\n}\n.menu-seq b.caret {\n  color: var(--asciidoctor-muted);\n  font-weight: 400;\n}\n\n/* \u2500\u2500 Media \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\naudio {\n  width: 100%;\n  max-width: 30rem;\n}\niframe {\n  border: 0;\n  max-width: 100%;\n}\n\n/* \u2500\u2500 Alignment and float roles \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\n.text-left {\n  text-align: left;\n}\n.text-center {\n  text-align: center;\n}\n.text-right {\n  text-align: right;\n}\nimg.left,\nfigure.left {\n  float: left;\n  margin: 0.25rem 1.25rem 0.75rem 0;\n}\nimg.right,\nfigure.right {\n  float: right;\n  margin: 0.25rem 0 0.75rem 1.25rem;\n}\n\n/* \u2500\u2500 General-purpose roles \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\n.underline {\n  text-decoration: underline;\n}\n.overline {\n  text-decoration: overline;\n}\n.line-through {\n  text-decoration: line-through;\n}\n.nobreak {\n  hyphens: none;\n  word-wrap: normal;\n}\n.nowrap {\n  white-space: nowrap;\n}\n.pre-wrap {\n  white-space: pre-wrap;\n}\n\n.unstyled {\n  list-style: none;\n  padding-left: 0;\n}\nul.no-bullet,\nol.unnumbered {\n  list-style: none;\n  padding-left: 1.25rem;\n}\n\n/* \u2500\u2500 Print \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n\n@media print {\n  :root {\n    --asciidoctor-bg: #fff;\n    --asciidoctor-surface: #f4f4f4;\n    --asciidoctor-fg: #000;\n    --asciidoctor-muted: #444;\n    --asciidoctor-line: #bbb;\n    --asciidoctor-link: #000;\n  }\n  body {\n    max-width: none;\n    font-size: 10.5pt;\n  }\n  a[href^=\"http\"]::after {\n    content: \" (\" attr(href) \")\";\n    font-size: 0.85em;\n    color: var(--asciidoctor-muted);\n  }\n  nav.toc a::after,\n  a.footnote-backref::after,\n  sup.footnote-ref a::after,\n  a.anchor::after,\n  h1 > a.link::after,\n  h2 > a.link::after,\n  h3 > a.link::after,\n  h4 > a.link::after,\n  h5 > a.link::after,\n  h6 > a.link::after {\n    content: none;\n  }\n  hr.page-break {\n    border: 0;\n    margin: 0;\n    break-after: page;\n  }\n  figure,\n  blockquote,\n  aside.admonition,\n  aside.sidebar,\n  table,\n  pre {\n    break-inside: avoid;\n  }\n  h1,\n  h2,\n  h3,\n  h4,\n  h5,\n  h6 {\n    break-after: avoid;\n  }\n}\n\n@media not print {\n  hr.page-break {\n    border: 0;\n    margin: 2.5rem auto;\n    text-align: center;\n  }\n  hr.page-break::after {\n    content: \"\u00B7 \u00B7 \u00B7\";\n    color: var(--asciidoctor-muted);\n    letter-spacing: 0.5em;\n  }\n}";
export default _default;
